export class DashboardComponent {
  checkScreen() {
    this.isMobile = window.innerWidth <= 768;
  }
  constructor(router, authService) {
    this.router = router;
    this.authService = authService;
    this.medicines = [];
    this.medicineName = '';
    this.medicineTime = '';
    this.bpRecords = [];
    this.bpDates = [];
    this.currentBP = [];
    this.previousBP = [];
    this.filteredBP = [];
    this.systolic = [];
    this.diastolic = [];
    this.pulse = [];
    this.prescriptions = [];
    this.analyzedPrescriptionId = null;
    this.selectedPrescriptionId = null;
    this.showAll = false;
    this.isMobile = false;
    this.isSidebarOpen = false;
    this.reminders = [];
  }
  ngOnInit() {
    this.loadBP();
    this.authService.getPrescriptions().subscribe(data => {
      this.prescriptions = data;
    });
    this.authService.getProfile().subscribe({
      next: res => {
        this.profile = res;
        // Calculate health score AFTER profile loads
        this.profile.healthScore = this.calculateHealthScore();
        // Wait for DOM to render
        setTimeout(() => {
          this.createChart();
        }, 100);
      },
      error: err => {
        console.log(err);
      }
    });
    this.authService.getLatestAdditionalInfo().subscribe(data => {
      this.latestInfo = data;
    });
    // Load reminders
    this.authService.getReminders().subscribe(data => {
      console.log("REMINDERS FROM DB:", data);
      this.reminders = data;
    });
    this.checkScreen();
    window.addEventListener('resize', () => this.checkScreen());
    this.checkScreen();
  }
  // HEALTH SCORE
  calculateHealthScore() {
    if (!this.profile) return 0;
    let score = 0;
    const bmi = this.profile.bmi;
    const diseases = this.profile.knownDiseases || [];
    if (bmi >= 18.5 && bmi < 25) {
      score = 90;
    } else if (bmi >= 25 && bmi < 30) {
      score = 70;
    } else if (bmi < 18.5) {
      score = 65;
    } else {
      score = 50;
    }
    score -= diseases.length * 10;
    if (score < 20) score = 20;
    return score;
  }
  // CHART
  createChart() {
    if (!this.profile?.bmi) return;
    const canvas = document.getElementById("bmiChart");
    if (!canvas) return;
    new Chart(canvas, {
      type: 'bar',
      data: {
        labels: ['Your BMI'],
        datasets: [{
          label: 'BMI',
          data: [this.profile.bmi]
        }]
      }
    });
  }
  // AI PLAN
  getPlan() {
    this.authService.getAIPlan(this.profile).subscribe({
      next: res => {
        console.log("PLAN:", res);
        this.aiPlan = res;
      },
      error: err => {
        console.error(err);
      }
    });
  }
  // REMINDERS
  setReminder() {
    if (!this.medicineName || !this.medicineTime) return;
    this.authService.addReminder({
      medicineName: this.medicineName,
      time: this.medicineTime
    }).subscribe(newReminder => {
      this.reminders.push(newReminder);
      this.medicineName = '';
      this.medicineTime = '';
    });
  }
  deleteReminder(index) {
    const reminder = this.reminders[index];
    this.authService.deleteReminder(reminder.id).subscribe(() => {
      this.reminders.splice(index, 1);
    });
  }
  editReminder(index) {
    this.reminders[index].editing = true;
  }
  saveReminder(index) {
    const reminder = this.reminders[index];
    this.authService.updateReminder(reminder.id, {
      name: reminder.name,
      time: reminder.time
    }).subscribe(() => {
      reminder.editing = false;
    });
  }
  cancelEdit(index) {
    this.reminders[index].editing = false;
  }
  addReminder(med, time) {
    this.authService.addReminder({
      medicineName: med.name,
      time: time
    }).subscribe(newReminder => {
      this.reminders = [...this.reminders, {
        id: newReminder.id,
        name: newReminder.name,
        time: newReminder.time,
        editing: false
      }];
    });
  }
  isReminderAdded(med, time) {
    if (!this.reminders?.length) return false;
    const compareName = this.cleanString(med.name);
    const compareTime = this.cleanTime(time);
    return this.reminders.some(r => {
      const reminderName = this.cleanString(r.name);
      const reminderTime = this.cleanTime(r.time);
      return reminderName === compareName && reminderTime === compareTime;
    });
  }
  cleanString(value) {
    if (!value) return '';
    return value.toString().trim().toLowerCase().replace(/\s+/g, ' '); // remove extra spaces
  }

  cleanTime(value) {
    if (!value) return '';
    const t = value.toString().trim().toUpperCase();
    if (t === 'PRN') return 'PRN';
    if (t.includes(':')) return t.substring(0, 5);
    return t;
  }
  normalizeTime(time) {
    if (!time) return '';
    const t = time.toString().trim().toUpperCase();
    // Handle PRN
    if (t === 'PRN') return 'PRN';
    // Handle HH:MM:SS
    if (t.includes(':')) {
      return t.substring(0, 5);
    }
    return t;
  }
  addBP() {
    const data = {
      systolic: this.systolic,
      diastolic: this.diastolic,
      pulse: this.pulse
    };
    this.authService.addBloodPressure(data).subscribe(() => {
      this.systolic;
      this.diastolic;
      this.pulse;
      this.loadBP();
    });
  }
  loadBP() {
    this.authService.getBloodPressure().subscribe(data => {
      this.bpRecords = data;
      this.processBPData();
      console.log("All BP:", this.bpRecords);
      console.log("Current Week:", this.currentBP);
    });
  }
  getBPStatus(s, d) {
    if (s >= 180 || d > 120) {
      return "Hypertensive Crisis";
    }
    if (s >= 140 || d >= 90) {
      return "Stage 2 Hypertension";
    }
    if (s >= 130 || d >= 80) {
      return "Stage 1 Hypertension";
    }
    if (s >= 120 && d < 80) {
      return "Elevated";
    }
    return "Normal";
  }
  getBPClass(s, d) {
    if (s >= 180 || d >= 120) {
      return "crisis";
    }
    if (s >= 140 || d >= 90) {
      return "stage2";
    }
    if (s >= 130 || d >= 80) {
      return "stage1";
    }
    if (s >= 120 && d < 80) {
      return "elevated";
    }
    return "normal";
  }
  applyFilter() {
    if (this.showAll) {
      this.filteredBP = this.bpRecords;
    } else {
      this.filteredBP = this.bpRecords.slice(0, 7); // Last 7 records
    }
  }

  toggleView() {
    this.showAll = !this.showAll;
    this.applyFilter();
  }
  processBPData() {
    if (!this.bpRecords || this.bpRecords.length === 0) {
      this.currentBP = [];
      this.previousBP = [];
      return;
    }
    // First 7 latest records = current week
    this.currentBP = this.bpRecords.slice(0, 7);
    const older = this.bpRecords.slice(7);
    const grouped = {};
    older.forEach(bp => {
      const date = new Date(bp.recorded_at);
      const weekStart = new Date(date);
      weekStart.setDate(date.getDate() - date.getDay());
      const key = weekStart.toDateString();
      if (!grouped[key]) {
        grouped[key] = [];
      }
      grouped[key].push(bp);
    });
    this.previousBP = Object.keys(grouped).map(key => ({
      weekStart: key,
      records: grouped[key],
      expanded: false
    }));
  }
  getLatestBP() {
    if (!this.bpRecords || this.bpRecords.length === 0) {
      return null;
    }
    return this.bpRecords[0]; // assuming newest first
  }

  arePrescriptionRemindersAdded(id) {
    if (!this.reminders || this.reminders.length === 0) {
      return false;
    }
    return true; // simple version (since we auto-add all)
  }

  togglePrescriptionMedicines(id) {
    // If already opened → close it
    if (this.selectedPrescriptionId === id) {
      this.selectedPrescriptionId = null;
      this.medicines = [];
      return;
    }
    // Otherwise load and show
    this.selectedPrescriptionId = id;
    this.authService.analyzePrescription(id).subscribe(res => {
      this.medicines = res.medicines || [];
    });
  }
  addRemindersFromPrescription(id) {
    this.analyzedPrescriptionId = id;
    this.authService.analyzePrescription(id).subscribe(res => {
      const meds = res.medicines || [];
      this.medicines = meds; // 🔥 IMPORTANT — store medicines
      meds.forEach(med => {
        med.times.forEach(time => {
          if (!this.isReminderAdded(med, time)) {
            this.authService.addReminder({
              medicineName: med.name,
              time: time
            }).subscribe(newReminder => {
              this.reminders = [...this.reminders, {
                id: newReminder.id,
                name: newReminder.name,
                time: newReminder.time,
                editing: false
              }];
            });
          }
        });
      });
    });
  }
  areAllMedicinesAdded() {
    if (!this.medicines || this.medicines.length === 0) {
      return false;
    }
    return this.medicines.every(med => med.times.every(time => this.isReminderAdded(med, time)));
  }
  // LOGOUT
  logout() {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
